# OEIS sequence: A236510

from sympy import factorint, primerange
def isok(n):
    if n==1: return True
    f=factorint(n)
    s=[f.get(p,0) for p in primerange(min(f),max(f)+1)]
    return s==s[::-1]
print([n for n in range(1,100) if isok(n)]) # _Jason Yuen_, May 02 2026

